#!/Users/FIRMAS/aster-bot/.venv/bin/python3
import json
import os
from typing import Dict, Any, Optional

STATE_PATH = os.path.expanduser(
    "~/.openclaw/workspace/skills/aster-trading/trade_state.json"
)


def _load_raw() -> Dict[str, Any]:
    if not os.path.exists(STATE_PATH):
        return {}
    try:
        with open(STATE_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _save_raw(state: Dict[str, Any]) -> None:
    os.makedirs(os.path.dirname(STATE_PATH), exist_ok=True)
    with open(STATE_PATH, "w", encoding="utf-8") as f:
        json.dump(state, f, ensure_ascii=False, indent=2)


def get_position_state(symbol: str) -> Optional[Dict[str, Any]]:
    state = _load_raw()
    return state.get(symbol)


def set_position_state(symbol: str, data: Dict[str, Any]) -> None:
    state = _load_raw()
    state[symbol] = data
    _save_raw(state)


def clear_position_state(symbol: str) -> None:
    state = _load_raw()
    if symbol in state:
        del state[symbol]
        _save_raw(state)
